// Pi extension: minimal kitty graphics integration.
//
// Scope is deliberately narrow:
//
//  * Apply the configured Pi theme (text colors only) at session start.
//  * Replace the editor input box's ASCII separator rails with kitty
//    placeholder PNG rules generated by `renderPromptEnclosure`.
//  * Keep low-level render primitives client-side by default. Operators can
//    opt into agent-callable render tools with PI_GRAPHICS_EXPOSE_RENDER_TOOLS=1.
//  * Expose `pi_graphics_clear` to scrub the images this extension owns.
//
// Everything else (splash, heartbeat, status chips, custom footer/header,
// terminal palette OSC, ambient APNG, conversation/transcript chrome,
// proof/showcase panels, ANSI/Braille/cockpit renderers, working-row branding)
// has been removed. The goal is to prove the graphics primitive layer before
// adding decorative chrome.

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";

import { Type } from "@sinclair/typebox";

import {
  ArminComponent,
  AssistantMessageComponent,
  BashExecutionComponent,
  BorderedLoader,
  BranchSummaryMessageComponent,
  CompactionSummaryMessageComponent,
  CustomEditor,
  CustomMessageComponent,
  DaxnutsComponent,
  DynamicBorder,
  ExtensionEditorComponent,
  ExtensionInputComponent,
  ExtensionSelectorComponent,
  FooterComponent,
  LoginDialogComponent,
  ModelSelectorComponent,
  OAuthSelectorComponent,
  SessionSelectorComponent,
  SettingsSelectorComponent,
  ShowImagesSelectorComponent,
  SkillInvocationMessageComponent,
  ThemeSelectorComponent,
  ThinkingSelectorComponent,
  ToolExecutionComponent,
  TreeSelectorComponent,
  UserMessageComponent,
  UserMessageSelectorComponent,
} from "@earendil-works/pi-coding-agent";

import {
  buildAnimationLoopCommand,
  buildKittyUnicodePlaceholderCell,
  buildPngCursorAnimationUpload,
  buildRelativePlacementCommand,
  bufferToBase64,
  buildDeleteByZIndexBandCommand,
  buildScopedDeleteCommand,
  detectKittyPassthroughMode,
  serializeKittyGraphicsCommand,
  serializeKittyGraphicsChunks,
  transparentPixelPngBase64,
} from "./kitty-graphics.js";
import {
  BOX_EFFECT_NAMES,
  BOX_TYPE_THEME_TOKENS,
  createBoxChromeRuntime,
  installBoxChromeMonkeyPatch,
} from "./pi-graphics/box-chrome.js";
import {
  buildWorkingIndicatorFrames,
  buildWorkingMessage,
} from "./pi-graphics/auto-widget.js";
import { getThemeColorHex, getThemeColorRgb } from "./pi-graphics/theme-colors.js";
import {
  piGraphicsImageId,
  piGraphicsPlacementId,
  piGraphicsPlaceholderPlacementId,
} from "./pi-graphics/id-space.js";
import {
  renderEditorBoxApng,
  renderEditorBorderFramesPngs,
  renderEditorRailApng,
  renderEditorCursorVline,
  renderGradientBorder,
  renderPromptEnclosure,
  resolveCellMetrics,
} from "./pi-graphics/affordances.js";
import {
  buildPlacement,
  ensureUnicodePlacement,
  makeState,
  renderToText,
  resetPlacementTracking,
} from "./pi-graphics/runtime.js";
import { PI_GRAPHICS_RESERVED_Z_INDICES, PI_GRAPHICS_Z } from "./pi-graphics/z-index.js";

const TOOL_PREFIX = "pi_graphics";
const FALSE_RE = /^(0|false|off|no|disabled)$/i;
const EDITOR_VARIANTS = ["rule", "gradient", "scanlines", "grid", "dots", "glow"];
const MAX_DECORATED_NOTIFICATION_LINES = 64;

function readJsonIfExists(path) {
  try {
    if (!path || !existsSync(path)) return null;
    return JSON.parse(readFileSync(path, "utf8"));
  } catch {
    return null;
  }
}

function agentDir() {
  return process.env.PI_CODING_AGENT_DIR || join(homedir(), ".pi", "agent");
}

function agentSettingsPath() {
  return join(agentDir(), "settings.json");
}

function modeIsOff(mode) {
  return typeof mode === "string" && FALSE_RE.test(mode.trim());
}

export function settingsEnvFromPiGraphics(settings = {}) {
  const gfx = settings.piGraphics || settings.kittyGraphics || {};
  const off = modeIsOff(gfx.mode);
  const features = gfx.features || {};
  const editor = gfx.editor || {};
  const env = {
    PI_GRAPHICS_MODE: off ? "off" : "on",
    PI_GRAPHICS_AUTO_THEME: off ? "0" : (gfx.autoApplyTheme ?? true) ? "1" : "0",
    PI_GRAPHICS_AUTO_EDITOR_SURFACE: off ? "0" : (features.editor ?? true) ? "1" : "0",
    PI_GRAPHICS_AUTO_EDITOR_CURSOR: off ? "0" : (features.editorCursor ?? features.cursor ?? editor.cursor ?? true) ? "1" : "0",
    PI_GRAPHICS_AUTO_FOOTER: off ? "0" : (features.footer ?? true) ? "1" : "0",
    PI_GRAPHICS_CELL_WIDTH_PX: gfx.cell?.widthPx != null ? String(gfx.cell.widthPx) : undefined,
    PI_GRAPHICS_CELL_HEIGHT_PX: gfx.cell?.heightPx != null ? String(gfx.cell.heightPx) : undefined,
    PI_GRAPHICS_LINE_HEIGHT_SCALE: gfx.cell?.lineHeightScale != null ? String(gfx.cell.lineHeightScale) : undefined,
    PI_GRAPHICS_EDITOR_VARIANT: editor.variant != null ? String(editor.variant) : undefined,
    PI_GRAPHICS_EDITOR_ALPHA: editor.alpha != null ? String(editor.alpha) : undefined,
    PI_GRAPHICS_EDITOR_FRAMES: editor.frames != null ? String(editor.frames) : undefined,
    PI_GRAPHICS_EDITOR_DELAY_MS: editor.delayMs != null ? String(editor.delayMs) : undefined,
    PI_GRAPHICS_EDITOR_STYLE: editor.style != null ? String(editor.style) : undefined,
    PI_GRAPHICS_AUTO_BOX_CHROME: off ? "0" : gfx.boxChrome === false ? "0" : "1",
    PI_GRAPHICS_EXPOSE_RENDER_TOOLS: gfx.exposeRenderTools != null ? String(gfx.exposeRenderTools) : undefined,
    PI_GRAPHICS_BOX_EFFECT: gfx.boxEffect != null ? String(gfx.boxEffect) : undefined,
    PI_GRAPHICS_BOX_MODE: gfx.boxMode != null ? String(gfx.boxMode) : "unicode",
    PI_GRAPHICS_DEBUG: gfx.debug != null ? String(gfx.debug) : undefined,
    PI_GRAPHICS_DEBUG_PLACEHOLDERS: gfx.debugPlaceholders != null ? String(gfx.debugPlaceholders) : undefined,
  };
  return Object.fromEntries(Object.entries(env).filter(([, value]) => value !== undefined));
}

export default function piGraphicsExtension(pi) {
  const settings = readJsonIfExists(agentSettingsPath()) || {};
  let settingsEnv = settingsEnvFromPiGraphics(settings);
  const gfxEnv = () => ({ ...settingsEnv, ...process.env });
  const configuredThemeName = String(settings.piGraphics?.theme || settings.kittyGraphics?.theme || settings.theme || "");
  const state = makeState();
  const footerState = {
    model: null,
    provider: null,
    contextUsed: 0,
    contextMax: 0,
    contextPct: 0,
    compactions: 0,
    compactMode: "auto",
  };

  function envBool(name, fallback = false) {
    const value = gfxEnv()[name];
    if (value === undefined) return fallback;
    return !FALSE_RE.test(String(value).trim());
  }

  function cellMetrics() {
    const env = gfxEnv();
    return resolveCellMetrics({
      cellWidthPx: env.PI_GRAPHICS_CELL_WIDTH_PX,
      cellHeightPx: env.PI_GRAPHICS_CELL_HEIGHT_PX,
      lineHeightScale: env.PI_GRAPHICS_LINE_HEIGHT_SCALE ?? 1.2,
    });
  }

  function editorVariant() {
    const env = gfxEnv();
    const raw = String(env.PI_GRAPHICS_EDITOR_VARIANT || "").trim().toLowerCase();
    return EDITOR_VARIANTS.includes(raw) ? raw : "gradient";
  }

  function editorAlpha() {
    const env = gfxEnv();
    const raw = Number(env.PI_GRAPHICS_EDITOR_ALPHA);
    return Number.isFinite(raw) ? Math.max(0, Math.min(1, raw)) : 0.55;
  }

  function editorPaddingX() {
    const raw = Number(settings.editorPaddingX);
    return Number.isFinite(raw) ? Math.max(0, Math.min(8, Math.trunc(raw))) : 0;
  }

  function editorStyle() {
    const env = gfxEnv();
    const raw = String(env.PI_GRAPHICS_EDITOR_STYLE || "").trim().toLowerCase();
    if (raw === "animated") return "animated";
    if (raw === "unicode" || raw === "placeholder" || raw === "caco") return "unicode";
    return "static";
  }

  function editorAnimationFrames() {
    const env = gfxEnv();
    const raw = Number(env.PI_GRAPHICS_EDITOR_FRAMES);
    return Number.isFinite(raw) ? Math.max(1, Math.min(256, Math.trunc(raw))) : 24;
  }

  function editorAnimationDelayMs() {
    const env = gfxEnv();
    const raw = Number(env.PI_GRAPHICS_EDITOR_DELAY_MS);
    return Number.isFinite(raw) ? Math.max(8, Math.min(2000, Math.trunc(raw))) : 17;
  }

  let writeGraphicsCommand = null;
  let hardwareCursorTui = null;
  function resolveGraphicsWriter(ctx) {
    if (typeof ctx?.ui?.write === "function") return ctx.ui.write.bind(ctx.ui);
    if (typeof ctx?.ui?.terminal?.write === "function") return ctx.ui.terminal.write.bind(ctx.ui.terminal);
    if (typeof ctx?.terminal?.write === "function") return ctx.terminal.write.bind(ctx.terminal);
    return null;
  }
  function emitGraphicsCommand(command) {
    if (!command || typeof writeGraphicsCommand !== "function") return;
    try { writeGraphicsCommand(command); } catch {}
  }

  function cursorStylingEnabled() {
    return !modeIsOff(gfxEnv().PI_GRAPHICS_MODE)
      && envBool("PI_GRAPHICS_AUTO_EDITOR_SURFACE", true)
      && envBool("PI_GRAPHICS_AUTO_EDITOR_CURSOR", true);
  }

  function installHardwareCursorGuard(tui) {
    if (!tui || typeof tui.setShowHardwareCursor !== "function" || typeof tui.getShowHardwareCursor !== "function") return null;
    hardwareCursorTui = tui;
    if (!tui.__piGraphicsHardwareCursorGuard) {
      const originalSet = tui.setShowHardwareCursor.bind(tui);
      const originalGet = tui.getShowHardwareCursor.bind(tui);
      const guard = { active: false, previous: undefined, originalSet, originalGet };
      tui.setShowHardwareCursor = (enabled) => {
        if (guard.active) {
          guard.previous = Boolean(enabled);
          return guard.originalSet(false);
        }
        return guard.originalSet(Boolean(enabled));
      };
      tui.__piGraphicsHardwareCursorGuard = guard;
    }
    return tui.__piGraphicsHardwareCursorGuard;
  }

  function applyHardwareCursorPolicy(tui = hardwareCursorTui) {
    const guard = installHardwareCursorGuard(tui);
    if (!guard) return;
    if (cursorStylingEnabled()) {
      if (!guard.active) guard.previous = guard.originalGet();
      guard.active = true;
      guard.originalSet(false);
    } else if (guard.active) {
      guard.active = false;
      guard.originalSet(Boolean(guard.previous));
      guard.previous = undefined;
    }
  }

  function restoreHardwareCursorPolicy() {
    const tui = hardwareCursorTui;
    const guard = tui?.__piGraphicsHardwareCursorGuard;
    if (!guard) return;
    if (guard.active) {
      guard.active = false;
      guard.originalSet(Boolean(guard.previous));
      guard.previous = undefined;
    }
  }

  function applyTheme(ctx) {
    if (!envBool("PI_GRAPHICS_AUTO_THEME", true) || !configuredThemeName) return;
    try { ctx.ui?.setTheme?.(configuredThemeName); } catch {}
  }

  // Track which images have already been uploaded so we never resend payload.
  const uploadedImages = new Set();
  const relativeUploaded = new Set();
  let editorBackgroundPlacementKey = null;
  const ZERO_WIDTH_CONTROL_RE = /\x1b\[[0-?]*[ -/]*[@-~]|\x1b\][\s\S]*?(?:\x07|\x1b\\)|\x1b[_P][\s\S]*?\x1b\\/g;

  function resetGraphicsUploadCaches() {
    uploadedImages.clear();
    relativeUploaded.clear();
    editorBackgroundPlacementKey = null;
  }

  function approximateVisibleCells(text) {
    return String(text || "").replace(ZERO_WIDTH_CONTROL_RE, "").length;
  }

  function formatFooterTokens(n) {
    const value = Number(n) || 0;
    if (value >= 1_000_000) {
      const scaled = value / 1_000_000;
      return `${scaled >= 10 ? scaled.toFixed(0) : scaled.toFixed(1).replace(/\.0$/, "")}m`;
    }
    if (value >= 1_000) {
      const scaled = value / 1_000;
      return `${scaled >= 10 ? scaled.toFixed(0) : scaled.toFixed(1).replace(/\.0$/, "")}k`;
    }
    return `${Math.round(value)}`;
  }

  function formatFooterPct(pct) {
    const value = Number.isFinite(Number(pct)) ? Number(pct) : 0;
    return `${value.toFixed(1).replace(/\.0$/, "")}%`;
  }

  function prettyFooterCwd(cwd) {
    const home = process.env.HOME;
    const value = cwd || process.cwd();
    if (home && value === home) return "~";
    if (home && value?.startsWith?.(`${home}/`)) return `~/${value.slice(home.length + 1)}`;
    return value;
  }

  function truncateFooterStart(text, width) {
    const chars = Array.from(String(text ?? ""));
    if (chars.length <= width) return chars.join("");
    if (width <= 0) return "";
    if (width === 1) return "…";
    return `…${chars.slice(chars.length - width + 1).join("")}`;
  }

  function truncateFooterEnd(text, width) {
    const chars = Array.from(String(text ?? ""));
    if (chars.length <= width) return chars.join("");
    if (width <= 0) return "";
    if (width === 1) return "…";
    return `${chars.slice(0, width - 1).join("")}…`;
  }

  function compactFooterModeLabel() {
    const envMode = process.env.PI_COMPACT_MODE;
    if (envMode && envMode !== "standard") return envMode;
    return footerState.compactMode || "auto";
  }

  function refreshFooterContext(ctx) {
    try {
      const usage = ctx?.getContextUsage?.();
      if (!usage) return;
      const used = usage.tokens ?? usage.contextTokens ?? usage.usedTokens ?? usage.totalTokens
        ?? (Number(usage.inputTokens || 0) + Number(usage.cacheCreationInputTokens || usage.cacheWriteTokens || 0) + Number(usage.cacheReadInputTokens || usage.cacheReadTokens || 0));
      const max = usage.contextWindowSize ?? usage.contextWindow ?? usage.maxTokens ?? footerState.contextMax;
      const pct = typeof usage.percent === "number" ? usage.percent
        : typeof usage.usedPercentage === "number" ? usage.usedPercentage
        : max > 0 ? (used / max) * 100
        : footerState.contextPct;
      footerState.contextUsed = used || footerState.contextUsed;
      footerState.contextMax = max || footerState.contextMax;
      footerState.contextPct = Math.round((pct || 0) * 10) / 10;
    } catch {}
  }

  function refreshFooterSession(ctx) {
    try {
      const branch = ctx?.sessionManager?.getBranch?.() || [];
      footerState.compactions = branch.filter((entry) => entry?.type === "compaction").length;
    } catch {}
  }

  function refreshFooterModel(event, ctx) {
    const model = event?.model || ctx?.model;
    if (model) {
      footerState.model = model.id || footerState.model;
      footerState.provider = model.provider || footerState.provider;
    }
  }

  function refreshFooterState(ctx, pi, event) {
    refreshFooterModel(event, ctx);
    refreshFooterContext(ctx);
    refreshFooterSession(ctx);
    try { footerState.compactMode = pi?.getCompactMode?.() || footerState.compactMode; } catch {}
  }

  function ensureAnchorUploaded({ anchorImageId, anchorPlacementId }) {
    if (uploadedImages.has(anchorImageId)) return;
    // Upload a 1×1 transparent PNG for the anchor image.
    const upload = serializeKittyGraphicsChunks({
      a: "t",
      f: 100,
      t: "d",
      i: anchorImageId,
      q: 2,
    }, transparentPixelPngBase64(), { passthrough: state.config.passthrough });
    // Create the virtual placement that Unicode placeholders will anchor to.
    const place = serializeKittyGraphicsCommand({
      a: "p",
      i: anchorImageId,
      p: anchorPlacementId,
      U: 1,
      c: 1,
      r: 1,
      z: PI_GRAPHICS_Z.SURFACE,
      q: 2,
    }, "", { passthrough: state.config.passthrough });
    emitGraphicsCommand(`${upload}${place}`);
    state.ownedImageIds.add(anchorImageId);
    uploadedImages.add(anchorImageId);
  }

  function ensureRelativeAnimUploaded({ animImageId, anchorImageId, anchorPlacementId, animPlacementId, pngs, delayMs, columns, rows, frames }) {
    const key = `${animImageId}->${anchorImageId}/${anchorPlacementId}`;
    if (relativeUploaded.has(key)) return;
    // Upload animation frames to the non-virtual animated image id.
    if (!uploadedImages.has(animImageId)) {
      const upload = buildPngCursorAnimationUpload({
        imageId: animImageId,
        pngBases: pngs.map((png) => bufferToBase64(png)),
        delaysMs: delayMs,
        passthrough: state.config.passthrough,
      });
      emitGraphicsCommand(upload);
      state.ownedImageIds.add(animImageId);
      uploadedImages.add(animImageId);
    }
    // Create a relative non-virtual placement attached to the anchor.
    const rel = buildRelativePlacementCommand({
      imageId: animImageId,
      placementId: animPlacementId,
      parentImageId: anchorImageId,
      parentPlacementId: anchorPlacementId,
      columns,
      rows,
      zIndex: PI_GRAPHICS_Z.SURFACE,
      passthrough: state.config.passthrough,
    });
    // Now that the non-virtual relative placement exists, let the terminal run
    // the animation loop natively. The earlier U=1 virtual placement path did
    // not repaint on s=3/v=1, but relative placements are ordinary placements
    // whose position is inherited from the virtual anchor.
    const start = buildAnimationLoopCommand({
      imageId: animImageId,
      passthrough: state.config.passthrough,
    });
    emitGraphicsCommand(`${rel}${start}`);
    relativeUploaded.add(key);
  }

  function buildEditorBorderRow(width, edge) {
    if (!ensureUnicodePlacement(state)) return null;
    const cols = Math.max(8, Math.min(512, Math.trunc(Number(width) || 0)));
    const cell = cellMetrics();
    const variant = editorVariant();
    const alpha = editorAlpha();
    const visualCols = cols;
    const leadingCells = 0;
    const frames = editorStyle() === "animated" ? editorAnimationFrames() : 1;
    const delayMs = editorAnimationDelayMs();
    if (frames <= 1) {
      const borderColor = getThemeColorHex(activeThemeRef, "accent", "#88c0d0");
      const glowColor = getThemeColorHex(activeThemeRef, "borderAccent", "#b48ead");
      const rendered = renderEditorBorderFramesPngs({
        columns: visualCols,
        edge,
        ...cell,
        frames: 1,
        borderColor,
        glowColor,
        borderAlpha: Math.max(0.32, Math.min(0.6, alpha)),
        glowAlpha: Math.max(0.22, alpha * 0.62),
      });
      const placement = buildPlacement(state, {
        name: `editor-border-static-${edge}-${visualCols}-${variant}-${alpha.toFixed(2)}-${cell.cellWidthPx}x${cell.cellHeightPx}`,
        png: rendered.pngs[0],
        columns: rendered.columns,
        rows: rendered.rows,
        width: visualCols,
        zIndex: PI_GRAPHICS_Z.SURFACE,
      });
      emitGraphicsCommand(placement.transmit);
      const line = placement.lines[0] ?? "";
      return `${" ".repeat(leadingCells)}${line}${" ".repeat(Math.max(0, cols - leadingCells - visualCols))}`;
    }
    // Animated path: virtual Unicode placeholder anchor + non-virtual relative
    // animation placement. Per-edge image ids prevent the two edges from
    // sharing a frame counter or placement.
    const borderColor = getThemeColorHex(activeThemeRef, "accent", "#88c0d0");
    const glowColor = getThemeColorHex(activeThemeRef, "borderAccent", "#b48ead");
    const rendered = renderEditorBorderFramesPngs({
      columns: visualCols,
      edge,
      ...cell,
      frames,
      borderColor,
      glowColor,
      borderAlpha: Math.max(0.32, Math.min(0.6, alpha)),
      glowAlpha: Math.max(0.22, alpha * 0.62),
    });
    const anchorKey = `editor-border-anchor-${edge}-${visualCols}-${cell.cellWidthPx}x${cell.cellHeightPx}`;
    const animKey = `editor-border-anim-${edge}-${visualCols}-${variant}-${alpha.toFixed(2)}-${cell.cellWidthPx}x${cell.cellHeightPx}-${frames}`;
    const anchorImageId = piGraphicsImageId(anchorKey);
    const animImageId = piGraphicsImageId(animKey);
    const anchorPlacementId = piGraphicsPlaceholderPlacementId(`editor-border-anchor-placement-${edge}-${visualCols}`);
    const animPlacementId = piGraphicsPlacementId(`editor-border-anim-placement-${edge}-${visualCols}`);
    ensureAnchorUploaded({ anchorImageId, anchorPlacementId });
    ensureRelativeAnimUploaded({
      animImageId,
      anchorImageId,
      anchorPlacementId,
      animPlacementId,
      pngs: rendered.pngs,
      delayMs,
      columns: rendered.columns,
      rows: rendered.rows,
      frames,
    });
    // Render the editor row as a single Unicode placeholder cell at column 0
    // followed by transparent spaces. The placeholder anchors the virtual
    // placement; the relative non-virtual animation placement follows it.
    const anchorCell = buildKittyUnicodePlaceholderCell({
      imageId: anchorImageId,
      placementId: anchorPlacementId,
      row: 0,
      column: 0,
      includeColumn: true,
    });
    const ESC = "\x1b";
    const low24 = anchorImageId % 0x1000000;
    const placementLow24 = anchorPlacementId % 0x1000000;
    const fg = `${ESC}[38;2;${(low24 >> 16) & 0xff};${(low24 >> 8) & 0xff};${low24 & 0xff}m`;
    const underline = `${ESC}[58;2;${(placementLow24 >> 16) & 0xff};${(placementLow24 >> 8) & 0xff};${placementLow24 & 0xff}m`;
    const reset = `${ESC}[39;59m`;
    const filler = " ".repeat(Math.max(0, visualCols - 1));
    const chrome = `${fg}${underline}${anchorCell}${reset}${filler}`;
    return `${" ".repeat(leadingCells)}${chrome}${" ".repeat(Math.max(0, cols - leadingCells - visualCols))}`;
  }

  function buildStatusIndicatorPrefix() {
    if (!ensureUnicodePlacement(state)) return "";
    const cell = cellMetrics();
    const rendered = renderPromptEnclosure({
      columns: 1,
      variant: "glow",
      alpha: Math.max(0.18, editorAlpha() * 0.38),
      leftColor: getThemeColorHex(activeThemeRef, "borderAccent", "#b48ead"),
      rightColor: getThemeColorHex(activeThemeRef, "accent", "#88c0d0"),
      fadeEdges: false,
      ...cell,
    });
    const placement = buildPlacement(state, {
      name: `status-indicator-${cell.cellWidthPx}x${cell.cellHeightPx}`,
      png: rendered.png,
      columns: rendered.columns,
      rows: rendered.rows,
      width: 1,
      zIndex: PI_GRAPHICS_Z.SURFACE,
    });
    emitGraphicsCommand(placement.transmit);
    return placement.lines[0] ?? "";
  }

  function decorateStatusValue(value) {
    if (typeof value !== "string" || value.length === 0 || value.includes("\u{10eeee}")) return value;
    const prefix = buildStatusIndicatorPrefix();
    return prefix ? `${prefix}${value}` : value;
  }

  function decorateNotificationValue(value) {
    if (typeof value !== "string" || value.length === 0) return value;
    if (!value.includes("\n")) return decorateStatusValue(value);
    let decoratedLines = 0;
    return value.split("\n").map((line) => {
      if (!line.length || decoratedLines >= MAX_DECORATED_NOTIFICATION_LINES) return line;
      decoratedLines += 1;
      return decorateStatusValue(line);
    }).join("\n");
  }

  function decorateWorkingMessage(value) {
    return decorateStatusValue(value);
  }

  function decorateWorkingIndicatorConfig(config) {
    if (!config || config.piGraphics === false || config.piGraphics?.enabled === false) return config;
    if (!Array.isArray(config.frames) || config.frames.length === 0) return config;
    return {
      ...config,
      frames: config.frames.map((frame) => decorateStatusValue(frame)),
    };
  }

  function buildEditorWorkspaceTail(width) {
    if (!ensureUnicodePlacement(state)) return null;
    const cols = Math.max(1, Math.min(256, Math.trunc(Number(width) || 0)));
    if (cols < 2) return null;
    const cell = cellMetrics();
    const rendered = renderPromptEnclosure({
      columns: cols,
      variant: "glow",
      alpha: Math.max(0.16, editorAlpha() * 0.34),
      leftColor: getThemeColorHex(activeThemeRef, "borderAccent", "#b48ead"),
      rightColor: getThemeColorHex(activeThemeRef, "accent", "#88c0d0"),
      fadeEdges: true,
      ...cell,
    });
    const placement = buildPlacement(state, {
      name: `editor-workspace-tail-${cols}-${cell.cellWidthPx}x${cell.cellHeightPx}`,
      png: rendered.png,
      columns: rendered.columns,
      rows: rendered.rows,
      width: cols,
      zIndex: PI_GRAPHICS_Z.SURFACE,
    });
    emitGraphicsCommand(placement.transmit);
    return placement.lines[0] ?? null;
  }

  function fillEditorTrailingWorkspace(line) {
    if (editorStyle() !== "unicode") return line;
    const match = String(line || "").match(/ +$/);
    if (!match || match[0].length < 2) return line;
    const tail = buildEditorWorkspaceTail(match[0].length);
    if (!tail) return line;
    return `${String(line).slice(0, -match[0].length)}${tail}`;
  }

  function ensureEditorRowBackground({ parentImageId, parentPlacementId, rowWidth, cursorCol }) {
    if (!ensureUnicodePlacement(state) || rowWidth < 2) return;
    const safeRowWidth = Math.max(1, Math.min(512, Math.trunc(Number(rowWidth) || 1) - 2));
    const safeCursorCol = Math.max(0, Math.min(safeRowWidth - 1, Math.trunc(Number(cursorCol) || 0)));
    const cell = cellMetrics();
    const bgImageId = piGraphicsImageId(`editor-row-background-${safeRowWidth}-${cell.cellWidthPx}x${cell.cellHeightPx}`);
    if (!uploadedImages.has(bgImageId)) {
      const rendered = renderPromptEnclosure({
        columns: safeRowWidth,
        variant: "glow",
        alpha: Math.max(0.10, editorAlpha() * 0.24),
        leftColor: getThemeColorHex(activeThemeRef, "borderAccent", "#b48ead"),
        rightColor: getThemeColorHex(activeThemeRef, "accent", "#88c0d0"),
        fadeEdges: true,
        ...cell,
      });
      emitGraphicsCommand(serializeKittyGraphicsChunks({
        a: "t",
        f: 100,
        t: "d",
        i: bgImageId,
        q: 2,
      }, bufferToBase64(rendered.png), { passthrough: state.config.passthrough }));
      state.ownedImageIds.add(bgImageId);
      uploadedImages.add(bgImageId);
    }
    const bgPlacementId = piGraphicsPlacementId("editor-row-background-relative");
    const key = `${bgImageId}:${parentImageId}:${parentPlacementId}:${safeRowWidth}:${safeCursorCol}`;
    if (editorBackgroundPlacementKey === key) return;
    emitGraphicsCommand(buildRelativePlacementCommand({
      imageId: bgImageId,
      placementId: bgPlacementId,
      parentImageId,
      parentPlacementId,
      hOffset: -safeCursorCol,
      columns: safeRowWidth,
      rows: 1,
      zIndex: PI_GRAPHICS_Z.BACKGROUND,
      passthrough: state.config.passthrough,
    }));
    editorBackgroundPlacementKey = key;
  }

  function buildEditorCursorCell({ rowWidth = 1, cursorCol = 0 } = {}) {
    if (!ensureUnicodePlacement(state)) return null;
    const cell = cellMetrics();
    const rendered = renderEditorCursorVline({
      alpha: Math.max(0.32, editorAlpha() * 0.72),
      backgroundColor: getThemeColorHex(activeThemeRef, "editorBg", "#101729"),
      coreColor: getThemeColorHex(activeThemeRef, "text", "#eceff4"),
      glowColor: getThemeColorHex(activeThemeRef, "accent", "#88c0d0"),
      ...cell,
    });
    const placement = buildPlacement(state, {
      name: `editor-cursor-${cell.cellWidthPx}x${cell.cellHeightPx}`,
      png: rendered.png,
      columns: rendered.columns,
      rows: rendered.rows,
      width: 1,
      zIndex: PI_GRAPHICS_Z.SURFACE,
    });
    emitGraphicsCommand(placement.transmit);
    // Do not attach a row-wide background to the cursor placement. It moves as
    // the cursor moves, which makes the editor backing drift horizontally while
    // typing. The stable editor rail widgets provide non-shifting chrome.
    return placement.lines[0] ?? null;
  }

  function replaceEditorCursorChrome(line, rowWidth = 1) {
    const text = String(line || "");
    if (!text.includes("\x1b[7m")) return line;
    const match = /\x1b\[7m[^\x1b]*\x1b\[0m/.exec(text);
    if (!match) return line;
    const cursorCol = approximateVisibleCells(text.slice(0, match.index));
    const cursor = buildEditorCursorCell({ rowWidth, cursorCol });
    if (!cursor) return line;
    return `${text.slice(0, match.index)}${cursor}${text.slice(match.index + match[0].length)}`;
  }

  function decorateEditorContentLine(line, rowWidth) {
    return fillEditorTrailingWorkspace(replaceEditorCursorChrome(line, rowWidth));
  }

  function footerSegmentValues(ctx, footerData, pi) {
    const branch = (() => {
      try { return footerData?.getGitBranch?.() || "no-branch"; } catch { return "no-branch"; }
    })();
    const context = footerState.contextMax > 0
      ? `${formatFooterPct(footerState.contextPct)}/${formatFooterTokens(footerState.contextMax)}`
      : "context n/a";
    const model = footerState.model
      ? `${footerState.provider ? `${footerState.provider}/` : ""}${footerState.model}`
      : "model n/a";
    return [
      { key: "cwd", token: "muted", value: prettyFooterCwd(ctx?.cwd || process.cwd()), truncate: truncateFooterStart, min: 4, max: 34 },
      { key: "branch", token: "accent", value: branch, truncate: truncateFooterEnd, min: 4, max: 24 },
      { key: "context", token: "thinkingXhigh", value: context, truncate: truncateFooterEnd, min: 5, max: 18 },
      { key: "compact", token: "borderAccent", value: `${compactFooterModeLabel()} (${footerState.compactions})`, truncate: truncateFooterEnd, min: 5, max: 16 },
      { key: "model", token: "customMessageLabel", value: model, truncate: truncateFooterEnd, min: 8, max: 36 },
      { key: "thinking", token: "muted", value: pi?.getThinkingLevel?.() || "off", truncate: truncateFooterEnd, min: 3, max: 12 },
    ];
  }

  function fitFooterSegments(rawSegments, width) {
    const terminalWidth = Math.max(1, Math.trunc(Number(width) || 1));
    const anchorCount = rawSegments.length + 1;
    let budget = terminalWidth - anchorCount;
    if (budget < rawSegments.length) return null;
    const segments = rawSegments.map((segment) => {
      const preferred = Math.min(segment.max, approximateVisibleCells(segment.value) + 2);
      return { ...segment, width: Math.max(segment.min, preferred) };
    });
    let used = segments.reduce((sum, segment) => sum + segment.width, 0);
    const shrinkOrder = [4, 0, 1, 3, 2, 5];
    while (used > budget) {
      let changed = false;
      for (const index of shrinkOrder) {
        const segment = segments[index];
        if (segment && segment.width > segment.min) {
          segment.width -= 1;
          used -= 1;
          changed = true;
          if (used <= budget) break;
        }
      }
      if (!changed) break;
    }
    if (used < budget && segments.length) segments[0].width += budget - used;
    return segments.map((segment) => {
      const innerWidth = Math.max(0, segment.width - 2);
      const text = segment.truncate(segment.value, innerWidth);
      const padded = ` ${text}${" ".repeat(Math.max(0, innerWidth - approximateVisibleCells(text)))} `;
      return { ...segment, text: padded };
    });
  }

  function ensureFooterSegmentBackground({ anchor, segmentKey, index, width, token }) {
    const textWidth = Math.max(1, Math.min(128, Math.trunc(Number(width) || 1)));
    const cell = cellMetrics();
    const color = getThemeColorHex(activeThemeRef, token || "accent", "#88c0d0");
    const imageId = piGraphicsImageId(`footer-bg-${segmentKey}-${textWidth}-${color}-${cell.cellWidthPx}x${cell.cellHeightPx}`);
    if (!uploadedImages.has(imageId)) {
      const rendered = renderPromptEnclosure({
        columns: textWidth,
        variant: "glow",
        alpha: Math.max(0.09, editorAlpha() * 0.20),
        leftColor: color,
        rightColor: getThemeColorHex(activeThemeRef, "editorBg", "#101729"),
        fadeEdges: true,
        ...cell,
      });
      emitGraphicsCommand(serializeKittyGraphicsChunks({
        a: "t",
        f: 100,
        t: "d",
        i: imageId,
        q: 2,
      }, bufferToBase64(rendered.png), { passthrough: state.config.passthrough }));
      state.ownedImageIds.add(imageId);
      uploadedImages.add(imageId);
    }
    const placementId = piGraphicsPlacementId(`footer-bg-${segmentKey}-${index}-${textWidth}`);
    const key = `footer-bg:${imageId}->${anchor.imageId}/${anchor.placementId}:${placementId}`;
    if (!relativeUploaded.has(key)) {
      emitGraphicsCommand(buildRelativePlacementCommand({
        imageId,
        placementId,
        parentImageId: anchor.imageId,
        parentPlacementId: anchor.placementId,
        hOffset: 1,
        columns: textWidth,
        rows: 1,
        zIndex: PI_GRAPHICS_Z.BACKGROUND,
        passthrough: state.config.passthrough,
      }));
      relativeUploaded.add(key);
    }
  }

  function buildFooterAnchorCell(segmentKey, index, token = "borderAccent") {
    if (!ensureUnicodePlacement(state)) return "│";
    const cell = cellMetrics();
    const color = getThemeColorHex(activeThemeRef, token, "#88c0d0");
    const rendered = renderPromptEnclosure({
      columns: 1,
      variant: "glow",
      alpha: Math.max(0.32, editorAlpha() * 0.64),
      leftColor: color,
      rightColor: getThemeColorHex(activeThemeRef, "thinkingXhigh", "#b48ead"),
      fadeEdges: false,
      ...cell,
    });
    const placement = buildPlacement(state, {
      name: `footer-anchor-${segmentKey}-${index}-${color}-${cell.cellWidthPx}x${cell.cellHeightPx}`,
      png: rendered.png,
      columns: 1,
      rows: 1,
      width: 1,
      zIndex: PI_GRAPHICS_Z.SURFACE,
    });
    emitGraphicsCommand(placement.transmit);
    return { cell: placement.lines[0] ?? "│", imageId: placement.imageId, placementId: placement.placementId };
  }

  function buildSegmentedFooterLine(ctx, footerData, width, pi, theme = activeThemeRef) {
    const rawSegments = footerSegmentValues(ctx, footerData, pi);
    const fitted = fitFooterSegments(rawSegments, width);
    if (!fitted) return truncateFooterEnd(" pi graphics ", Math.max(1, Math.trunc(Number(width) || 1)));
    const fg = typeof theme?.fg === "function" ? theme.fg.bind(theme) : (_token, text) => text;
    let line = "";
    fitted.forEach((segment, index) => {
      const anchor = buildFooterAnchorCell(segment.key, index, segment.token);
      if (anchor && typeof anchor === "object") {
        ensureFooterSegmentBackground({ anchor, segmentKey: segment.key, index, width: approximateVisibleCells(segment.text), token: segment.token });
        line += anchor.cell;
      } else {
        line += anchor;
      }
      line += fg(segment.token, segment.text);
    });
    const endAnchor = buildFooterAnchorCell("end", fitted.length, "borderAccent");
    line += typeof endAnchor === "object" ? endAnchor.cell : endAnchor;
    const visible = approximateVisibleCells(line);
    const target = Math.max(1, Math.trunc(Number(width) || 1));
    return visible > target ? truncateFooterEnd(line.replace(ZERO_WIDTH_CONTROL_RE, ""), target) : line;
  }

  function installSegmentedFooter(ctx, pi, event) {
    if (!envBool("PI_GRAPHICS_AUTO_FOOTER", true)) return false;
    if (typeof ctx?.ui?.setFooter !== "function") return false;
    refreshFooterState(ctx, pi, event);
    const factory = (tui, theme, footerData) => {
      writeGraphicsCommand = writeGraphicsCommand || resolveGraphicsWriter(tui) || resolveGraphicsWriter({ ui: tui });
      activeThemeRef = theme || ctx?.ui?.theme || activeThemeRef;
      const unsubscribe = (() => { try { return footerData?.onBranchChange?.(() => tui?.requestRender?.()); } catch { return null; } })();
      return {
        __piGraphicsNoWrap: true,
        piGraphics: false,
        dispose() { try { unsubscribe?.(); } catch {} },
        invalidate() {},
        render(width = 120) {
          refreshFooterState(ctx, pi);
          activeThemeRef = theme || ctx?.ui?.theme || activeThemeRef;
          return [buildSegmentedFooterLine(ctx, footerData, width, pi, activeThemeRef)];
        },
      };
    };
    factory.__piGraphicsNoWrap = true;
    factory.piGraphics = false;
    try { ctx.ui.setStatus?.("pi-graphics-footer", undefined); } catch {}
    try { ctx.ui.setFooter(factory, { piGraphics: false }); } catch { return false; }
    return true;
  }

  function buildEditorRailRows(width, edge) {
    if (!ensureUnicodePlacement(state)) return null;
    const cols = Math.max(8, Math.min(512, Math.trunc(Number(width) || 0)));
    const cell = cellMetrics();
    const variant = editorVariant();
    const alpha = editorAlpha();
    const frames = editorAnimationFrames();
    const delayMs = editorAnimationDelayMs();
    const apng = renderEditorRailApng({
      columns: cols,
      edge,
      ...cell,
      frames,
      delayMs,
      plays: 0,
      glowColor: variant === "glow" ? "#b48cff" : "#00d8ff",
      glowAlpha: Math.max(0.25, alpha * 0.7),
      rows: 2,
    });
    const placement = buildPlacement(state, {
      name: `editor-rail2-${edge}-${cols}-${variant}-${alpha.toFixed(2)}-${cell.cellWidthPx}x${cell.cellHeightPx}-${frames}@${delayMs}`,
      png: apng.png,
      columns: apng.columns,
      rows: apng.rows,
      width: cols,
      zIndex: PI_GRAPHICS_Z.SURFACE,
    });
    emitGraphicsCommand(placement.transmit);
    return placement.lines;
  }

  function isEditorChromeLine(line) {
    const text = String(line || "").replace(/\x1b\[[0-9;]*m/g, "").trim();
    if (text.length < 8) return false;
    if (!/[─━═]/.test(text)) return false;
    return /^[\s─━═╭╮╰╯╔╗╚╝┌┐└┘│┃┬┴┼·✧]+$/.test(text);
  }

  function installEditorSurface(ctx) {
    if (!envBool("PI_GRAPHICS_AUTO_EDITOR_SURFACE", true)) return false;
    if (typeof ctx.ui?.setEditorComponent !== "function") return false;
    if (typeof CustomEditor !== "function") return false;
    const isDashLine = (line) => {
      const text = String(line || "").replace(/\x1b\[[0-9;]*m/g, "").trim();
      return text.length > 0 && /^[\s─━═]+$/.test(text);
    };
    class KittyEditor extends CustomEditor {
      render(width) {
        const baseLines = super.render(width);
        if (!Array.isArray(baseLines) || baseLines.length < 2) return baseLines;
        const next = baseLines.slice();
        const dashIndices = [];
        for (let i = 0; i < next.length; i += 1) {
          if (isDashLine(next[i])) dashIndices.push(i);
        }
        if (dashIndices.length === 0) return baseLines;
        const firstDash = dashIndices[0];
        const lastDash = dashIndices[dashIndices.length - 1];
        const top = buildEditorBorderRow(width, "top");
        const bot = firstDash !== lastDash ? buildEditorBorderRow(width, "bottom") : null;
        if (!top) return baseLines;
        next[firstDash] = top;
        if (bot && lastDash !== firstDash) next[lastDash] = bot;
        return next.map((line, index) => dashIndices.includes(index) ? line : decorateEditorContentLine(line, width));
      }
    }
    ctx.ui.setEditorComponent((tui, theme, keybindings) => {
      writeGraphicsCommand = writeGraphicsCommand || resolveGraphicsWriter(tui) || resolveGraphicsWriter({ ui: tui });
      applyHardwareCursorPolicy(tui);
      return new KittyEditor(tui, theme, keybindings);
    });
    return true;
  }

  function looksLikeDashRender(component) {
    if (!component || typeof component.render !== "function") return false;
    if (component.__piGraphicsDashPatched) return false;
    try {
      const sample = component.render(8);
      if (!Array.isArray(sample) || sample.length !== 1) return false;
      const text = String(sample[0] ?? "").replace(/\x1b\[[0-9;]*m/g, "");
      return /^[─━═]{2,}$/.test(text);
    } catch {
      return false;
    }
  }

  function wrapDashRender(component) {
    const original = component.render.bind(component);
    component.__piGraphicsDashPatched = true;
    component.render = (width) => {
      const line = buildEditorBorderRow(width, "symmetric");
      return line ? [line] : original(width);
    };
  }

  function walkAndPatch(node, depth = 0) {
    if (!node || depth > 32) return;
    if (looksLikeDashRender(node)) wrapDashRender(node);
    const kids = Array.isArray(node.children) ? node.children : null;
    if (kids) for (const child of kids) walkAndPatch(child, depth + 1);
  }

  function patchDashRendersForTui(tui) {
    if (!ensureUnicodePlacement(state)) return;
    if (!tui) return;
    walkAndPatch(tui, 0);
    let attempts = 0;
    const id = setInterval(() => {
      attempts += 1;
      try { walkAndPatch(tui, 0); } catch {}
      if (attempts >= 40) clearInterval(id);
    }, 500);
    if (typeof id.unref === "function") id.unref();
  }


  function mountEditorRails(ctx) {
    if (!envBool("PI_GRAPHICS_AUTO_EDITOR_SURFACE", true)) return;
    if (typeof ctx.ui?.setWidget !== "function") return;
    const factory = (edge) => (_tui, _theme) => ({
      __piGraphicsNoWrap: true,
      piGraphics: false,
      render(width) {
        const lines = buildEditorRailRows(width, edge);
        return lines && lines.length ? lines : ["", ""];
      },
      invalidate() {},
    });
    try { ctx.ui.setWidget("pi-graphics-editor-top", factory("top"), { placement: "aboveEditor" }); } catch {}
    try { ctx.ui.setWidget("pi-graphics-editor-bottom", factory("bottom"), { placement: "belowEditor" }); } catch {}
  }

  let boxChromeInstalled = false;
  let boxChromeRuntime = null;
  let restoreBuiltInBoxChrome = null;
  let genericGraphicsInstanceCounter = 0;
  let activeThemeRef = null;

  function nextGenericGraphicsInstanceId() {
    genericGraphicsInstanceCounter = (genericGraphicsInstanceCounter + 1) & 0xffff;
    return `generic-${genericGraphicsInstanceCounter}`;
  }

  function shouldSkipGraphicsWrap(value) {
    return !!(value && (value.__piGraphicsNoWrap || value.piGraphics === false || value.piGraphics?.enabled === false));
  }

  function shouldSkipGraphicsOptions(options) {
    return !!(options && (options.piGraphics === false || options.piGraphics?.enabled === false));
  }

  function wrapRenderableComponent(component, type = "customTui") {
    if (!boxChromeRuntime) return component;
    if (!component || typeof component.render !== "function") return component;
    if (shouldSkipGraphicsWrap(component)) return component;
    if (component.__piGraphicsGenericWrapped) return component;
    const originalRender = component.render.bind(component);
    const instanceId = component.__piGraphicsGenericInstanceId || nextGenericGraphicsInstanceId();
    try {
      component.render = (width) => {
        const lines = originalRender(width);
        if (!Array.isArray(lines)) return lines;
        try {
          return boxChromeRuntime.applyToRows({
            type,
            instanceId,
            lines,
            component,
            renderWidth: width,
          });
        } catch {
          return lines;
        }
      };
      component.__piGraphicsGenericWrapped = true;
      component.__piGraphicsGenericInstanceId = instanceId;
    } catch {
      return component;
    }
    return component;
  }

  function wrapRenderableFactory(value, type = "customTui") {
    if (!boxChromeRuntime || value == null) return value;
    if (shouldSkipGraphicsWrap(value)) return value;
    if (Array.isArray(value)) {
      const lines = value.slice();
      const component = {
        __piGraphicsStaticLines: true,
        render(_width) { return lines.slice(); },
        invalidate() {},
      };
      return wrapRenderableComponent(component, type);
    }
    if (typeof value === "function") {
      if (value.__piGraphicsFactoryWrapped || shouldSkipGraphicsWrap(value)) return value;
      const wrapped = function (...args) {
        const component = value.apply(this, args);
        if (component && typeof component.then === "function") {
          return component.then((resolved) => wrapRenderableFactory(resolved, type));
        }
        return wrapRenderableFactory(component, type);
      };
      wrapped.__piGraphicsFactoryWrapped = true;
      return wrapped;
    }
    return wrapRenderableComponent(value, type);
  }

  function patchUiGraphicsSurfaces(ctx) {
    const ui = ctx?.ui;
    if (!boxChromeRuntime || !ui || ui.__piGraphicsSurfacesPatched) return;
    const originals = {
      notify: typeof ui.notify === "function" ? ui.notify : null,
      custom: typeof ui.custom === "function" ? ui.custom : null,
      setWidget: typeof ui.setWidget === "function" ? ui.setWidget : null,
      setFooter: typeof ui.setFooter === "function" ? ui.setFooter : null,
      setHeader: typeof ui.setHeader === "function" ? ui.setHeader : null,
      setEditorComponent: typeof ui.setEditorComponent === "function" ? ui.setEditorComponent : null,
      setStatus: typeof ui.setStatus === "function" ? ui.setStatus : null,
      setWorkingMessage: typeof ui.setWorkingMessage === "function" ? ui.setWorkingMessage : null,
      setWorkingIndicator: typeof ui.setWorkingIndicator === "function" ? ui.setWorkingIndicator : null,
      setHiddenThinkingLabel: typeof ui.setHiddenThinkingLabel === "function" ? ui.setHiddenThinkingLabel : null,
    };
    ui.__piGraphicsOriginalSurfaces = originals;
    ui.__piGraphicsSurfacesPatched = true;
    if (originals.notify) {
      const patchedNotify = function (message, type = undefined, ...rest) {
        const options = rest.find((item) => item && typeof item === "object" && ("piGraphics" in item));
        const next = shouldSkipGraphicsOptions(options) ? message : decorateNotificationValue(message);
        return originals.notify.call(this, next, type, ...rest);
      };
      patchedNotify.__piGraphicsPatchedSurface = true;
      ui.notify = patchedNotify;
    }
    if (originals.custom) {
      const patchedCustom = function (componentOrFactory, options = undefined, ...rest) {
        const type = options?.overlay ? "overlay" : "customTui";
        const next = shouldSkipGraphicsOptions(options) ? componentOrFactory : wrapRenderableFactory(componentOrFactory, type);
        return originals.custom.call(this, next, options, ...rest);
      };
      patchedCustom.__piGraphicsPatchedSurface = true;
      ui.custom = patchedCustom;
    }
    if (originals.setWidget) {
      const patchedSetWidget = function (id, componentOrFactory, options = undefined, ...rest) {
        const next = shouldSkipGraphicsOptions(options) ? componentOrFactory : wrapRenderableFactory(componentOrFactory, "widget");
        return originals.setWidget.call(this, id, next, options, ...rest);
      };
      patchedSetWidget.__piGraphicsPatchedSurface = true;
      ui.setWidget = patchedSetWidget;
    }
    if (originals.setFooter) {
      const patchedSetFooter = function (componentOrFactory, ...rest) {
        const options = rest.find((item) => item && typeof item === "object" && ("piGraphics" in item));
        const next = shouldSkipGraphicsOptions(options) ? componentOrFactory : wrapRenderableFactory(componentOrFactory, "footer");
        return originals.setFooter.call(this, next, ...rest);
      };
      patchedSetFooter.__piGraphicsPatchedSurface = true;
      ui.setFooter = patchedSetFooter;
    }
    if (originals.setHeader) {
      const patchedSetHeader = function (componentOrFactory, ...rest) {
        const options = rest.find((item) => item && typeof item === "object" && ("piGraphics" in item));
        const next = shouldSkipGraphicsOptions(options) ? componentOrFactory : wrapRenderableFactory(componentOrFactory, "header");
        return originals.setHeader.call(this, next, ...rest);
      };
      patchedSetHeader.__piGraphicsPatchedSurface = true;
      ui.setHeader = patchedSetHeader;
    }
    if (originals.setEditorComponent) {
      const patchedSetEditorComponent = function (componentOrFactory, ...rest) {
        const options = rest.find((item) => item && typeof item === "object" && ("piGraphics" in item));
        const next = shouldSkipGraphicsOptions(options) ? componentOrFactory : wrapRenderableFactory(componentOrFactory, "editor");
        return originals.setEditorComponent.call(this, next, ...rest);
      };
      patchedSetEditorComponent.__piGraphicsPatchedSurface = true;
      ui.setEditorComponent = patchedSetEditorComponent;
    }
    if (originals.setStatus) {
      const patchedSetStatus = function (id, value, ...rest) {
        const options = rest.find((item) => item && typeof item === "object" && ("piGraphics" in item));
        const next = shouldSkipGraphicsOptions(options) ? value : decorateStatusValue(value);
        return originals.setStatus.call(this, id, next, ...rest);
      };
      patchedSetStatus.__piGraphicsPatchedSurface = true;
      ui.setStatus = patchedSetStatus;
    }
    if (originals.setWorkingMessage) {
      const patchedSetWorkingMessage = function (value, ...rest) {
        const options = rest.find((item) => item && typeof item === "object" && ("piGraphics" in item));
        const next = shouldSkipGraphicsOptions(options) ? value : decorateWorkingMessage(value);
        return originals.setWorkingMessage.call(this, next, ...rest);
      };
      patchedSetWorkingMessage.__piGraphicsPatchedSurface = true;
      ui.setWorkingMessage = patchedSetWorkingMessage;
    }
    if (originals.setWorkingIndicator) {
      const patchedSetWorkingIndicator = function (config, ...rest) {
        const next = decorateWorkingIndicatorConfig(config);
        return originals.setWorkingIndicator.call(this, next, ...rest);
      };
      patchedSetWorkingIndicator.__piGraphicsPatchedSurface = true;
      ui.setWorkingIndicator = patchedSetWorkingIndicator;
    }
    if (originals.setHiddenThinkingLabel) {
      const patchedSetHiddenThinkingLabel = function (label, ...rest) {
        const options = rest.find((item) => item && typeof item === "object" && ("piGraphics" in item));
        const next = shouldSkipGraphicsOptions(options) ? label : decorateStatusValue(label);
        return originals.setHiddenThinkingLabel.call(this, next, ...rest);
      };
      patchedSetHiddenThinkingLabel.__piGraphicsPatchedSurface = true;
      ui.setHiddenThinkingLabel = patchedSetHiddenThinkingLabel;
    }
  }

  function restoreUiGraphicsSurfaces(ctx) {
    const ui = ctx?.ui;
    const originals = ui?.__piGraphicsOriginalSurfaces;
    if (!ui || !ui.__piGraphicsSurfacesPatched || !originals) return;
    if (originals.notify && ui.notify?.__piGraphicsPatchedSurface) ui.notify = originals.notify;
    if (originals.custom && ui.custom?.__piGraphicsPatchedSurface) ui.custom = originals.custom;
    if (originals.setWidget && ui.setWidget?.__piGraphicsPatchedSurface) ui.setWidget = originals.setWidget;
    if (originals.setFooter && ui.setFooter?.__piGraphicsPatchedSurface) ui.setFooter = originals.setFooter;
    if (originals.setHeader && ui.setHeader?.__piGraphicsPatchedSurface) ui.setHeader = originals.setHeader;
    if (originals.setEditorComponent && ui.setEditorComponent?.__piGraphicsPatchedSurface) ui.setEditorComponent = originals.setEditorComponent;
    if (originals.setStatus && ui.setStatus?.__piGraphicsPatchedSurface) ui.setStatus = originals.setStatus;
    if (originals.setWorkingMessage && ui.setWorkingMessage?.__piGraphicsPatchedSurface) ui.setWorkingMessage = originals.setWorkingMessage;
    if (originals.setWorkingIndicator && ui.setWorkingIndicator?.__piGraphicsPatchedSurface) ui.setWorkingIndicator = originals.setWorkingIndicator;
    if (originals.setHiddenThinkingLabel && ui.setHiddenThinkingLabel?.__piGraphicsPatchedSurface) ui.setHiddenThinkingLabel = originals.setHiddenThinkingLabel;
    delete ui.__piGraphicsOriginalSurfaces;
    delete ui.__piGraphicsSurfacesPatched;
  }

  function teardownBoxChrome(ctx) {
    restoreUiGraphicsSurfaces(ctx);
    try { restoreBuiltInBoxChrome?.(); } catch {}
    restoreBuiltInBoxChrome = null;
    boxChromeRuntime = null;
    boxChromeInstalled = false;
  }

  function installBoxChromeOnce(ctx, { force = false } = {}) {
    if (force) teardownBoxChrome(ctx);
    if (boxChromeInstalled) return;
    if (modeIsOff(gfxEnv().PI_GRAPHICS_MODE) || !envBool("PI_GRAPHICS_AUTO_BOX_CHROME", true)) {
      teardownBoxChrome(ctx);
      return;
    }
    const runtime = createBoxChromeRuntime({
      emitGraphicsCommand,
      state,
      passthrough: state.config.passthrough,
      cellWidthPx: cellMetrics().cellWidthPx,
      cellHeightPx: cellMetrics().cellHeightPx,
      boxEffect: gfxEnv().PI_GRAPHICS_BOX_EFFECT,
      boxMode: String(gfxEnv().PI_GRAPHICS_BOX_MODE || "relative").toLowerCase() === "unicode" ? "unicode" : "relative",
      debugPlaceholders: envBool("PI_GRAPHICS_DEBUG_PLACEHOLDERS", envBool("PI_GRAPHICS_DEBUG", false)),
      resolveTheme({ type } = {}) {
        const token = (type && BOX_TYPE_THEME_TOKENS[type]) || "accent";
        const colorRgb = getThemeColorRgb(activeThemeRef, token, "#88c0d0");
        return { colorRgb };
      },
    });
    boxChromeRuntime = runtime;
    const patch = installBoxChromeMonkeyPatch({
      components: {
        assistant: AssistantMessageComponent,
        tool: ToolExecutionComponent,
        bash: BashExecutionComponent,
        user: UserMessageComponent,
        custom: CustomMessageComponent,
        skill: SkillInvocationMessageComponent,
        branch: BranchSummaryMessageComponent,
        compaction: CompactionSummaryMessageComponent,
        footer: FooterComponent,
        loader: BorderedLoader,
        border: DynamicBorder,
        input: ExtensionInputComponent,
        editor: ExtensionEditorComponent,
        selector: ExtensionSelectorComponent,
        login: LoginDialogComponent,
        model: ModelSelectorComponent,
        oauth: OAuthSelectorComponent,
        session: SessionSelectorComponent,
        settings: SettingsSelectorComponent,
        image: ShowImagesSelectorComponent,
        theme: ThemeSelectorComponent,
        thinkingSelector: ThinkingSelectorComponent,
        tree: TreeSelectorComponent,
        userSelector: UserMessageSelectorComponent,
        agent: ArminComponent,
        mascot: DaxnutsComponent,
      },
      runtime,
    });
    restoreBuiltInBoxChrome = typeof patch?.restore === "function" ? patch.restore : null;
    boxChromeInstalled = true;
    patchUiGraphicsSurfaces(ctx);
  }

  pi.on("session_start", async (_event, ctx) => {
    if (modeIsOff(gfxEnv().PI_GRAPHICS_MODE)) return;
    writeGraphicsCommand = resolveGraphicsWriter(ctx);
    activeThemeRef = ctx?.ui?.theme || null;
    applyTheme(ctx);
    installEditorSurface(ctx);
    installSegmentedFooter(ctx, pi, _event);
    try {
      ctx.ui?.setWorkingIndicator?.({
        intervalMs: 110,
        frames: buildWorkingIndicatorFrames(ctx.ui.theme || activeThemeRef),
      });
      ctx.ui?.setWorkingMessage?.(buildWorkingMessage({ stage: "working" }, ctx.ui.theme || activeThemeRef));
    } catch {}
    installBoxChromeOnce(ctx);
    setDebugPanel(ctx, settings);
  });

  pi.on("model_select", async (event, ctx) => {
    refreshFooterState(ctx, pi, event);
    installSegmentedFooter(ctx, pi, event);
  });

  pi.on("message_end", async (event, ctx) => {
    refreshFooterState(ctx, pi, event);
    installSegmentedFooter(ctx, pi, event);
  });

  pi.on("turn_end", async (event, ctx) => {
    refreshFooterState(ctx, pi, event);
    installSegmentedFooter(ctx, pi, event);
  });

  pi.on("session_compact", async (event, ctx) => {
    footerState.compactions += 1;
    refreshFooterState(ctx, pi, event);
    installSegmentedFooter(ctx, pi, event);
  });

  function defaultGfxPresets(settings, ctx) {
    const currentTheme = String(settings.theme || settings.piGraphics?.theme || "kitty-graphics-nord");
    const themeNames = [];
    for (const name of [currentTheme, "kitty-graphics-nord", "kitty-graphics", "dark", "light"]) {
      if (name && !themeNames.includes(name)) themeNames.push(name);
    }
    const available = (() => {
      try { return new Set((ctx?.ui?.getAllThemes?.() || []).map((t) => t.name || t)); } catch { return null; }
    })();
    const themes = available ? themeNames.filter((name) => available.has(name)) : themeNames;
    const baseThemes = themes.length ? themes : [currentTheme];
    const presets = [];
    for (const theme of baseThemes) {
      presets.push({ name: `${theme}:static`, theme, mode: "on", editorStyle: "static", boxChrome: true, boxMode: "unicode", boxEffect: "glass" });
      presets.push({ name: `${theme}:unicode`, theme, mode: "on", editorStyle: "unicode", boxChrome: true, boxMode: "unicode", boxEffect: "cloud" });
      presets.push({ name: `${theme}:animated`, theme, mode: "on", editorStyle: "animated", boxChrome: false });
      for (const effect of BOX_EFFECT_NAMES) {
        presets.push({ name: `${theme}:boxes:${effect}`, theme, mode: "on", editorStyle: "static", boxChrome: true, boxMode: "relative", boxEffect: effect });
      }
    }
    presets.push({ name: "graphics-off", theme: currentTheme, mode: "off", editorStyle: "static", boxChrome: false });
    return presets;
  }

  function getGfxPresets(settings, ctx) {
    const configured = settings.piGraphics?.presets;
    if (Array.isArray(configured) && configured.length > 0) return configured;
    return defaultGfxPresets(settings, ctx);
  }

  function applyGfxPreset(settings, preset) {
    const gfx = (settings.piGraphics = settings.piGraphics || {});
    const editor = (gfx.editor = gfx.editor || {});
    if (preset.theme) {
      settings.theme = preset.theme;
      gfx.theme = preset.theme;
    }
    if (preset.mode) gfx.mode = preset.mode;
    if (preset.editorStyle) editor.style = preset.editorStyle;
    if (preset.editor?.style) editor.style = preset.editor.style;
    if (preset.boxChrome !== undefined) gfx.boxChrome = Boolean(preset.boxChrome);
    if (preset.boxEffect) gfx.boxEffect = preset.boxEffect;
    else if (preset.boxChrome === false) delete gfx.boxEffect;
    if (preset.boxMode) gfx.boxMode = preset.boxMode;
    else if (preset.boxChrome === false) delete gfx.boxMode;
    if (preset.features && typeof preset.features === "object") gfx.features = { ...(gfx.features || {}), ...preset.features };
    gfx.activePresetIndex = preset.index;
  }

  function saveSettings(settings) {
    mkdirSync(agentDir(), { recursive: true });
    writeFileSync(agentSettingsPath(), JSON.stringify(settings, null, 2) + "\n");
  }

  function applyGfxSettingsLive(ctx, settings) {
    settingsEnv = settingsEnvFromPiGraphics(settings);
    try {
      const themeName = settings.piGraphics?.theme || settings.theme;
      if (themeName) ctx?.ui?.setTheme?.(themeName);
      activeThemeRef = ctx?.ui?.theme || activeThemeRef;
    } catch {}
    if (modeIsOff(gfxEnv().PI_GRAPHICS_MODE) || !envBool("PI_GRAPHICS_AUTO_BOX_CHROME", true)) {
      teardownBoxChrome(ctx);
    } else {
      installBoxChromeOnce(ctx, { force: true });
    }
    applyHardwareCursorPolicy();
    try { ctx?.ui?.requestRender?.(true); } catch {}
  }

  async function applyGfxSettingsAndReload(ctx, settings, message = "Saved Pi Graphics settings. Reloading runtime to apply...") {
    try { saveSettings(settings); }
    catch (error) { ctx.ui.notify(`Failed to write settings: ${error?.message || String(error)}`, "error"); return false; }
    if (typeof ctx.reload === "function") {
      ctx.ui.notify(message, "info");
      try { await ctx.reload(); } catch {}
    } else {
      applyGfxSettingsLive(ctx, settings);
      ctx.ui.notify(message.replace(/\s*Reloading(?: runtime)?(?: to apply)?\.*/i, " Applied live."), "info");
    }
    return true;
  }

  async function cycleGfxPreset(ctx, direction = 1) {
    const settings = readJsonIfExists(agentSettingsPath()) || {};
    const gfx = (settings.piGraphics = settings.piGraphics || {});
    const presets = getGfxPresets(settings, ctx).map((p, index) => ({ ...p, index }));
    if (!presets.length) { ctx.ui.notify("No Pi Graphics presets configured.", "warning"); return; }
    const current = Number.isFinite(Number(gfx.activePresetIndex)) ? Number(gfx.activePresetIndex) : -1;
    const nextIndex = ((Math.trunc(current) + direction) % presets.length + presets.length) % presets.length;
    const preset = presets[nextIndex];
    applyGfxPreset(settings, preset);
    await applyGfxSettingsAndReload(ctx, settings, `Pi Graphics preset ${nextIndex + 1}/${presets.length}: ${preset.name || "unnamed"}. Reloading...`);
  }

  function themeProvenanceLines(ctx, settings) {
    const themes = (() => { try { return ctx?.ui?.getAllThemes?.() || []; } catch { return []; } })();
    const byName = new Map();
    for (const theme of themes) {
      const name = String(theme?.name || "unnamed");
      const entry = { name, path: theme?.path || theme?.sourcePath || "<builtin>" };
      const list = byName.get(name) || [];
      list.push(entry);
      byName.set(name, list);
    }
    const duplicates = [...byName.entries()].filter(([, entries]) => entries.length > 1);
    const configured = settings.piGraphics?.theme || settings.kittyGraphics?.theme || settings.theme || "(default)";
    const lines = [
      "Pi Graphics theme provenance:",
      `  configured theme: ${configured}`,
      `  settings file:     ${agentSettingsPath()}`,
      `  settings themes:   ${(settings.themes || []).join(", ") || "(none)"}`,
      `  loaded themes:     ${themes.length}`,
      `  duplicate names:   ${duplicates.length}`,
    ];
    for (const theme of themes) lines.push(`  - ${theme.name || "unnamed"}: ${theme.path || theme.sourcePath || "<builtin>"}`);
    for (const [name, entries] of duplicates) {
      lines.push(`  duplicate ${name}:`);
      for (const entry of entries) lines.push(`    * ${entry.path}`);
    }
    if (duplicates.length === 0) {
      lines.push("No duplicate theme names reported by the running Pi theme registry.");
    } else {
      lines.push("Remove redundant settings.json themes[] entries or stale copied theme files so the package-provided theme wins once.");
    }
    return lines;
  }

  function debugPanelLines(settings = readJsonIfExists(agentSettingsPath()) || {}) {
    const gfx = settings.piGraphics || {};
    return [
      "Pi Graphics debug",
      `mode=${gfx.mode ?? "on"} theme=${settings.theme || gfx.theme || "(default)"}`,
      `box=${gfx.boxChrome === false ? "off" : "on"} mode=${gfx.boxMode || "relative"} effect=${gfx.boxEffect || "per-type"}`,
      `debug=${gfx.debug ? "on" : "off"} placeholders=${(gfx.debugPlaceholders ?? gfx.debug) ? "visible U" : "kitty"}`,
      `cell=${gfx.cell?.widthPx || 8}x${gfx.cell?.heightPx || "auto"} line=${gfx.cell?.lineHeightScale || 1.2}`,
      "Use /gfx debug to toggle; /gfx box-effect auto for per-surface chrome.",
    ];
  }

  function setDebugPanel(ctx, settings = readJsonIfExists(agentSettingsPath()) || {}) {
    const gfx = settings.piGraphics || {};
    try {
      ctx?.ui?.setWidget?.("pi-graphics-debug", gfx.debug ? debugPanelLines(settings) : undefined, { placement: "belowEditor" });
    } catch {}
  }

  async function showGfxSettingsWindow(ctx, settings, gfx, editor) {
    const effects = ["auto", ...BOX_EFFECT_NAMES];
    const rows = [
      { key: "mode", label: "Mode", values: ["on", "off", "debug"], get: () => gfx.mode || "on", set: (v) => { gfx.mode = v; } },
      { key: "boxChrome", label: "Box chrome", values: ["on", "off"], get: () => gfx.boxChrome === false ? "off" : "on", set: (v) => { gfx.boxChrome = v === "on"; } },
      { key: "boxMode", label: "Box mode", values: ["relative", "unicode"], get: () => gfx.boxMode || "relative", set: (v) => { gfx.boxMode = v; gfx.boxChrome = true; } },
      { key: "boxEffect", label: "Box effect", values: effects, get: () => gfx.boxEffect || "auto", set: (v) => { if (v === "auto") delete gfx.boxEffect; else gfx.boxEffect = v; gfx.boxChrome = true; } },
      { key: "editor", label: "Editor", values: ["static", "unicode", "animated"], get: () => editor.style || "static", set: (v) => { editor.style = v; } },
      { key: "debug", label: "Debug panel", values: ["off", "on"], get: () => gfx.debug ? "on" : "off", set: (v) => { gfx.debug = v === "on"; gfx.debugPlaceholders = gfx.debug; } },
      { key: "placeholders", label: "Debug placeholders", values: ["off", "on"], get: () => gfx.debugPlaceholders ? "on" : "off", set: (v) => { gfx.debugPlaceholders = v === "on"; } },
    ];
    let selected = 0;
    const renderLine = (width, text) => String(text).slice(0, Math.max(1, width));
    const componentFactory = (_tui, theme, keybindings, done) => ({
      invalidate() {},
      render(width = 80) {
        const fg = typeof theme?.fg === "function" ? theme.fg.bind(theme) : (_token, text) => text;
        const lines = [
          fg("accent", "Pi Graphics settings"),
          fg("muted", "↑/↓ select  ←/→ change  Enter save+reload  d debug  q/Esc close"),
          "",
        ];
        rows.forEach((row, index) => {
          const marker = index === selected ? "→" : " ";
          const value = row.get();
          lines.push(`${marker} ${row.label.padEnd(20)} ${value}`);
        });
        lines.push("", "Preview:");
        lines.push("  assistant=manuscript  tool=schematic  oauth=keyring");
        lines.push("  model=dial  settings=slider  thinking=lantern");
        lines.push("  U placeholders appear in debug mode with unique truecolor IDs.");
        return lines.map((line) => renderLine(width, line));
      },
      handleInput(data) {
        const key = String(data || "");
        const matches = (name) => { try { return keybindings?.matches?.(data, name); } catch { return false; } };
        const move = (delta) => { selected = Math.max(0, Math.min(rows.length - 1, selected + delta)); };
        const change = (delta) => {
          const row = rows[selected];
          const values = row.values;
          const current = row.get();
          const index = Math.max(0, values.indexOf(current));
          row.set(values[(index + delta + values.length) % values.length]);
        };
        if (matches("tui.select.up") || key === "\x1b[A" || key === "k") move(-1);
        else if (matches("tui.select.down") || key === "\x1b[B" || key === "j") move(1);
        else if (matches("tui.select.left") || key === "\x1b[D" || key === "h") change(-1);
        else if (matches("tui.select.right") || key === "\x1b[C" || key === "l" || key === " ") change(1);
        else if (key.toLowerCase() === "d") { gfx.debug = !gfx.debug; gfx.debugPlaceholders = gfx.debug; }
        else if (matches("tui.select.confirm") || key === "\r" || key === "\n") done("save");
        else if (matches("tui.select.cancel") || key === "\x1b" || key.toLowerCase() === "q") done("close");
        try { _tui?.requestRender?.(); } catch {}
      },
    });
    const result = typeof ctx?.ui?.custom === "function"
      ? await ctx.ui.custom(componentFactory, { overlay: true, overlayOptions: { width: "70%", minWidth: 54, maxHeight: "80%", anchor: "center", margin: 1 } })
      : "notify";
    if (result === "save") {
      await applyGfxSettingsAndReload(ctx, settings, "Saved Pi Graphics settings. Reloading runtime to apply...");
    } else if (result === "notify") {
      ctx.ui.notify("This Pi runtime does not expose custom overlay UI; use /gfx status, /gfx box-effect auto, or /gfx debug.", "warning");
    }
    setDebugPanel(ctx, settings);
  }

  pi.registerCommand?.("gfx", {
    description: "Inspect or change Pi Graphics modes. Usage: /gfx [status|next|presets|themes|preset <n|name>|editor static|animated|box on|off|box-effect <name>|mode on|off|debug]",
    handler: async (args, ctx) => {
      const tokens = String(args || "").trim().split(/\s+/).filter(Boolean);
      const path = agentSettingsPath();
      const settings = readJsonIfExists(path) || {};
      const gfx = (settings.piGraphics = settings.piGraphics || {});
      const editor = (gfx.editor = gfx.editor || {});
      const describe = () => {
        const presets = getGfxPresets(settings, ctx);
        const lines = [
          "Pi Graphics settings:",
          `  mode:           ${gfx.mode ?? "on"}`,
          `  theme:          ${settings.theme || gfx.theme || "(default)"}`,
          `  editor.style:   ${editor.style ?? "static"} (also: unicode|animated)`,
          `  box chrome:     ${gfx.boxChrome === true ? "on" : "off"}`,
          `  box mode:       ${gfx.boxMode || "relative"} (also: unicode)`,
          `  box effect:     ${gfx.boxEffect || "per-type"} (also: ${BOX_EFFECT_NAMES.join("|")})`,
          `  active preset:  ${Number.isFinite(Number(gfx.activePresetIndex)) ? Number(gfx.activePresetIndex) + 1 : "none"}/${presets.length}`,
          "",
          "Usage: /gfx next | /gfx presets | /gfx themes | /gfx preset <n|name>",
          "       /gfx editor static|unicode|animated",
          "       /gfx box on|off",
          `       /gfx box-effect ${BOX_EFFECT_NAMES.join("|")}`,
          "       /gfx mode on|off|debug",
          "Ctrl+t cycles presets when keybindings free it from app.thinking.toggle.",
        ];
        ctx.ui.notify(lines.join("\n"), "info");
      };
      if (tokens.length === 0) { await showGfxSettingsWindow(ctx, settings, gfx, editor); return; }
      const action = String(tokens[0] || "").toLowerCase();
      if (action === "status" || action === "show" || action === "info") { describe(); return; }
      if (action === "debug") {
        gfx.debug = !gfx.debug;
        gfx.debugPlaceholders = gfx.debug;
        settingsEnv = settingsEnvFromPiGraphics(settings);
        try { saveSettings(settings); } catch (error) { ctx.ui.notify(`Failed to write settings: ${error?.message || String(error)}`, "error"); return; }
        setDebugPanel(ctx, settings);
        applyGfxSettingsLive(ctx, settings);
        ctx.ui.notify(`Pi Graphics debug ${gfx.debug ? "on" : "off"}. Placeholder diagnostics ${gfx.debugPlaceholders ? "visible" : "hidden"}.`, "info");
        return;
      }
      if (action === "next" || action === "cycle") { await cycleGfxPreset(ctx, 1); return; }
      if (action === "prev" || action === "previous") { await cycleGfxPreset(ctx, -1); return; }
      if (action === "presets") {
        const presets = getGfxPresets(settings, ctx);
        ctx.ui.notify(presets.map((p, i) => `${i + 1}. ${p.name || "unnamed"} — theme=${p.theme || settings.theme || "default"}, editor=${p.editorStyle || p.editor?.style || "static"}, box=${p.boxChrome ? "on" : "off"}, boxMode=${p.boxMode || "relative"}, effect=${p.boxEffect || "per-type"}, mode=${p.mode || "on"}`).join("\n"), "info");
        return;
      }
      if (action === "themes" || action === "theme-provenance") {
        ctx.ui.notify(themeProvenanceLines(ctx, settings).join("\n"), "info");
        return;
      }
      if (action === "preset") {
        const query = String(tokens[1] || "");
        const presets = getGfxPresets(settings, ctx).map((p, index) => ({ ...p, index }));
        const number = Number(query);
        const preset = Number.isFinite(number) ? presets[Math.trunc(number) - 1] : presets.find((p) => String(p.name || "").toLowerCase() === query.toLowerCase());
        if (!preset) { ctx.ui.notify(`Unknown Pi Graphics preset: ${query}`, "warning"); return; }
        applyGfxPreset(settings, preset);
        await applyGfxSettingsAndReload(ctx, settings, `Pi Graphics preset ${preset.index + 1}/${presets.length}: ${preset.name || "unnamed"}. Reloading...`);
        return;
      }
      let changed = false;
      for (let i = 0; i < tokens.length; i += 2) {
        const key = String(tokens[i] || "").toLowerCase();
        const value = String(tokens[i + 1] || "").toLowerCase();
        if (!key || !value) continue;
        if (key === "editor") {
          if (value === "static" || value === "animated" || value === "unicode") { editor.style = value; changed = true; }
          else ctx.ui.notify(`unknown editor style: ${value} (use static|unicode|animated)`, "warning");
        } else if (key === "box" || key === "box-chrome" || key === "boxchrome") {
          if (/^(on|true|1)$/.test(value)) { gfx.boxChrome = true; changed = true; }
          else if (/^(off|false|0)$/.test(value)) { gfx.boxChrome = false; changed = true; }
          else ctx.ui.notify(`unknown box value: ${value} (use on|off)`, "warning");
        } else if (key === "box-mode" || key === "boxmode") {
          if (value === "relative" || value === "unicode") { gfx.boxMode = value; gfx.boxChrome = true; changed = true; }
          else ctx.ui.notify(`unknown box mode: ${value} (use relative|unicode)`, "warning");
        } else if (key === "box-effect" || key === "boxeffect" || key === "effect") {
          if (BOX_EFFECT_NAMES.includes(value)) { gfx.boxEffect = value; gfx.boxChrome = true; changed = true; }
          else if (value === "auto" || value === "per-type" || value === "default") { delete gfx.boxEffect; changed = true; }
          else ctx.ui.notify(`unknown box effect: ${value} (use ${BOX_EFFECT_NAMES.join("|")} or auto)`, "warning");
        } else if (key === "mode") {
          if (/^(on|off|debug)$/.test(value)) { gfx.mode = value; changed = true; }
          else ctx.ui.notify(`unknown mode: ${value} (use on|off|debug)`, "warning");
        } else if (key === "theme") {
          settings.theme = value; gfx.theme = value; changed = true;
        } else {
          ctx.ui.notify(`unknown /gfx key: ${key}`, "warning");
        }
      }
      if (!changed) { describe(); return; }
      await applyGfxSettingsAndReload(ctx, settings);
    },
  });

  pi.registerShortcut?.("ctrl+t", {
    description: "Cycle Pi Graphics visual presets",
    handler: async (ctx) => cycleGfxPreset(ctx, 1),
  });

  pi.on("session_end", async (_event, ctx) => {
    teardownBoxChrome(ctx);
    restoreHardwareCursorPolicy();
    writeGraphicsCommand = null;
    try { ctx.ui?.setWidget?.("pi-graphics-editor-top", undefined); } catch {}
    try { ctx.ui?.setWidget?.("pi-graphics-editor-bottom", undefined); } catch {}
    try { if (envBool("PI_GRAPHICS_AUTO_FOOTER", true)) ctx.ui?.setFooter?.(undefined, { piGraphics: false }); } catch {}
    try {
      const command = buildScopedDeleteCommand({ ownedImageIds: state.ownedImageIds });
      if (command) resolveGraphicsWriter(ctx)?.(command);
    } catch {}
    resetGraphicsUploadCaches();
    resetPlacementTracking(state);
  });

  if (envBool("PI_GRAPHICS_EXPOSE_RENDER_TOOLS", false)) {
    pi.registerTool({
    name: `${TOOL_PREFIX}_render_prompt_enclosure`,
    label: "Pi Graphics: Prompt Enclosure",
    description: "Render a kitty-graphics PNG prompt enclosure (replacement for ASCII '----' separators) and return text containing the kitty transmit sequence plus Unicode placeholder cells.",
    parameters: Type.Object({
      columns: Type.Number({ description: "Width in terminal cells.", minimum: 1, maximum: 512 }),
      variant: Type.Optional(Type.String({ description: "Visual variant: rule, gradient, scanlines, grid, dots, glow." })),
      alpha: Type.Optional(Type.Number({ description: "Base alpha 0..1.", minimum: 0, maximum: 1 })),
      leftColor: Type.Optional(Type.String({ description: "Left/start CSS color." })),
      rightColor: Type.Optional(Type.String({ description: "Right/end CSS color." })),
      fadeEdges: Type.Optional(Type.Boolean({ description: "Fade alpha at start/end." })),
      cellWidthPx: Type.Optional(Type.Number({ minimum: 1, maximum: 64 })),
      cellHeightPx: Type.Optional(Type.Number({ minimum: 1, maximum: 96 })),
      lineHeightScale: Type.Optional(Type.Number({ minimum: 0.5, maximum: 3 })),
      caption: Type.Optional(Type.String()),
    }),
    async execute(_toolCallId, params) {
      if (!ensureUnicodePlacement(state)) {
        return { content: [{ type: "text", text: "─".repeat(Math.max(1, params.columns || 1)) }], details: { fallback: true } };
      }
      const rendered = renderPromptEnclosure({
        columns: params.columns,
        variant: params.variant,
        alpha: params.alpha,
        leftColor: params.leftColor,
        rightColor: params.rightColor,
        fadeEdges: params.fadeEdges,
        cellWidthPx: params.cellWidthPx,
        cellHeightPx: params.cellHeightPx,
        lineHeightScale: params.lineHeightScale,
      });
      const placement = buildPlacement(state, {
        name: `prompt-enclosure-${rendered.columns}-${rendered.variant}`,
        png: rendered.png,
        columns: rendered.columns,
        rows: rendered.rows,
        caption: params.caption,
      });
      return {
        content: [{ type: "text", text: renderToText(placement) }],
        details: {
          imageId: placement.imageId,
          placementId: placement.placementId,
          columns: rendered.columns,
          rows: rendered.rows,
          variant: rendered.variant,
        },
      };
    },
  });

  pi.registerTool({
    name: `${TOOL_PREFIX}_render_message_border`,
    label: "Pi Graphics: Message Border",
    description: "Render a kitty-graphics PNG gradient border block sized in terminal cells.",
    parameters: Type.Object({
      columns: Type.Number({ description: "Width in terminal cells.", minimum: 2, maximum: 512 }),
      rows: Type.Number({ description: "Height in terminal cells.", minimum: 2, maximum: 256 }),
      topColor: Type.Optional(Type.String()),
      bottomColor: Type.Optional(Type.String()),
      cornerRadius: Type.Optional(Type.Number({ minimum: 0, maximum: 32 })),
      borderThickness: Type.Optional(Type.Number({ minimum: 1, maximum: 8 })),
    }),
    async execute(_toolCallId, params) {
      if (!ensureUnicodePlacement(state)) {
        return { content: [{ type: "text", text: "" }], details: { fallback: true } };
      }
      const rendered = renderGradientBorder({
        columns: params.columns,
        rows: params.rows,
        topColor: params.topColor,
        bottomColor: params.bottomColor,
        cornerRadius: params.cornerRadius,
        borderThickness: params.borderThickness,
      });
      const placement = buildPlacement(state, {
        name: `message-border-${rendered.columns}x${rendered.rows}`,
        png: rendered.png,
        columns: rendered.columns,
        rows: rendered.rows,
      });
      return {
        content: [{ type: "text", text: renderToText(placement) }],
        details: {
          imageId: placement.imageId,
          placementId: placement.placementId,
          columns: rendered.columns,
          rows: rendered.rows,
        },
      };
    },
  });
  }

  pi.registerTool({
    name: `${TOOL_PREFIX}_clear`,
    label: "Pi Graphics: Clear",
    description: "Delete every kitty image owned by this extension. Scoped: never deletes images owned by others, never issues a global clear.",
    parameters: Type.Object({
      hostedBand: Type.Optional(Type.Boolean({ description: "Also clear the reserved Pi graphics z-index band for caco-hosted stale-view cleanup." })),
    }),
    async execute(_toolCallId, params = {}, _signal, _onUpdate, ctx) {
      const scoped = buildScopedDeleteCommand({ ownedImageIds: state.ownedImageIds });
      const hostedBand = params.hostedBand ? buildDeleteByZIndexBandCommand({ zIndices: PI_GRAPHICS_RESERVED_Z_INDICES }) : "";
      const command = `${scoped}${hostedBand}`;
      if (command) {
        try { resolveGraphicsWriter(ctx)?.(command); } catch {}
      }
      const cleared = state.ownedImageIds.size;
      try { boxChromeRuntime?.resetCaches?.(); } catch {}
      resetGraphicsUploadCaches();
      resetPlacementTracking(state);
      return { content: [{ type: "text", text: `cleared ${cleared} pi-graphics image(s)${params.hostedBand ? " and hosted z-index band" : ""}` }], details: { cleared, hostedBand: !!params.hostedBand, zIndices: params.hostedBand ? PI_GRAPHICS_RESERVED_Z_INDICES : [] } };
    },
  });
}
